  "finder": "keyword",
  "query": "Search for tools that can query the NHGRI-EBI GWAS Catalog for Alzheimer's Disease (EFO_0000249) to get associations, SNPs, and mapped genes.",
  "result": [
    {
      "name": "gwas_get_associations_by_disease",
      "description": "Retrieve genome-wide significant GWAS associations for a disease from the NHGRI-EBI GWAS Catalog REST API. Accepts EFO IDs (e.g., EFO_0000249) or MONDO IDs (auto-mapped to EFO).",
      "parameter": {
        "type": "object",
        "properties": {
          "efo_id": {
            "type": "str",
            "description": "EFO ID of the disease (e.g., \"EFO_0000249\" for Alzheimer's disease). MONDO IDs such as \"MONDO_0004975\" are automatically mapped to the correct GWAS Catalog EFO ID.",
            "required": true
          },
          "p_value_threshold": {
            "type": "float",
            "description": "P-value threshold for significance (default: 5e-8).",
            "required": true
          }
        }
      },
      "required": [
        "efo_id",
        "p_value_threshold"
      ],
      "source": "custom_registry"
    },
    {
      "name": "analyze_pdb_chain",
      "description": "Parses a PDB file, extracts a specified chain, counts VAL and TRP residues (alpha carbons), and calculates the distance between alpha carbons of two specified residues.",
      "parameter": {
        "type": "object",
        "properties": {
          "pdb_id": {
            "type": "str",
            "description": "The PDB ID (e.g., '1PC2').",
            "required": true
          },
          "chain_id": {
            "type": "str",
            "description": "The chain ID to analyze (e.g., 'A').",
            "required": true
          },
          "residue1_spec": {
            "type": "str",
            "description": "Optional: Specification for the first residue for distance calculation (e.g., 'ASP72'). Format: RESIDUE_NAME_3_LETTER_CODE + RESIDUE_NUMBER.",

